import jwt
from datetime import datetime, timedelta
import base64


def generate_token(user):
    exp = datetime.utcnow() + timedelta(days=1)

    payload = {
        'exp': exp,
        'data': user['id']
    }

    return jwt.encode(payload, 'secret', algorithm='HS256').decode('utf-8')